// lib/help-content.ts
// AskBiz Help Center — all content hardcoded, no database required
import { EXPANDED_HELP_TOPICS, EXPANDED_HELP_ARTICLES } from './help-content-expansion';

export interface HelpArticle {
  slug: string;
  title: string;
  description: string; // meta description for SEO
  topic: string;
  topicSlug: string;
  readTime: number; // minutes
  popular?: boolean;
  content: HelpSection[];
  faq?: HelpFAQ[];
  related?: string[]; // slugs
  keywords?: string[]; // SEO keywords
  lastUpdated: string;
}

export interface HelpSection {
  heading: string;
  body: string; // markdown-lite: supports **bold**, `code`, bullet lists with -
}

export interface HelpFAQ {
  q: string;
  a: string;
}

export interface HelpTopic {
  slug: string;
  title: string;
  description: string;
  icon: string;
  color: string;
  articles: string[]; // slugs
}

