HELP_TOPICS.push(...EXPANDED_HELP_TOPICS);
HELP_ARTICLES.push(...EXPANDED_HELP_ARTICLES);

// ─── HELPERS ──────────────────────────────────────────────────────────────────

export function getArticleBySlug(slug: string): HelpArticle | undefined {
  return HELP_ARTICLES.find((a) => a.slug === slug);
}

export function getArticlesByTopic(topicSlug: string): HelpArticle[] {
  return HELP_ARTICLES.filter((a) => a.topicSlug === topicSlug);
}

export function getPopularArticles(): HelpArticle[] {
  return HELP_ARTICLES.filter((a) => a.popular);
}

export function getTopicBySlug(slug: string): HelpTopic | undefined {
  return HELP_TOPICS.find((t) => t.slug === slug);
}

export function searchArticles(query: string): HelpArticle[] {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return HELP_ARTICLES.filter(
    (a) =>
      a.title.toLowerCase().includes(q) ||
      a.description.toLowerCase().includes(q) ||
      a.topic.toLowerCase().includes(q) ||
      a.content.some(
        (s) =>
          s.heading.toLowerCase().includes(q) ||
          s.body.toLowerCase().includes(q)
      ) ||
      (a.keywords && a.keywords.some((k) => k.toLowerCase().includes(q))) ||
      (a.faq && a.faq.some((f) => f.q.toLowerCase().includes(q) || f.a.toLowerCase().includes(q)))
  );
}
